                        <span className="mr-2">📧</span>
                        Contact Management
                    </h2>
                    <div className="flex flex-wrap gap-4 text-sm">
                        <span className={`${isDarkMode ? 'text-gray-400' : 'text-gray-600'} transition-colors duration-300`}>
