                        switch(activeTab) {
                            case 'overview':
                                return (
                                    <div className="animate-fadeIn">
                                        {renderAdminOverview()}
                                    </div>
                                );
                            case 'users':
                                return (
                                    <div className="animate-slideInLeft">
                                        {renderUserManagement()}
                                    </div>
                                );
                            case 'applications':
                                return (
                                    <div className="animate-slideInRight">
                                        {renderApplicationManagement()}
                                    </div>
                                );
                            case 'contacts':
                                return (
                                    <div className="animate-slideInUp">
                                        {renderContactManagement()}
                                    </div>
                                );
                            case 'settings':
                                return (
                                    <div className="animate-fadeIn">
                                        {renderAdminSettings()}
                                    </div>
